import * as Utilities from "lib/utilities";
import { decisions } from "./utilities.mock";
import { setItem } from "lib/localstorage";

describe("Utilities module", () => {
  describe("replacePlaceholders", () => {
    it("should replace the placeholders with the provided keys", () => {
      expect(
        Utilities.replacePlaceholders("Replace this: {{this}} and that: {{that}}", {
          this: "replacement 1",
          that: "replacement 2"
        })
      ).toBe("Replace this: replacement 1 and that: replacement 2");
    });
    it("should still return something if not all the keys are in the string", () => {
      expect(
        Utilities.replacePlaceholders("Replace this: {{this}} and that:", {
          this: "replacement 1",
          that: "replacement 2"
        })
      ).toBe("Replace this: replacement 1 and that:");
    });
    it("should return the original string if incorrect keys are provided", () => {
      expect(
        Utilities.replacePlaceholders("Replace this: {{this}} and that: {{that}}", {
          something: "replacement 1",
          else: "replacement 2"
        })
      ).toBe("Replace this: {{this}} and that: {{that}}");
    });
    it("should return the original string if a string with nothing to replace is provided", () => {
      expect(
        Utilities.replacePlaceholders("Nothing to replace", {
          something: "replacement 1",
          else: "replacement 2"
        })
      ).toBe("Nothing to replace");
    });
    it("should return an empty string if neither a string or keys are provided", () => {
      expect(Utilities.replacePlaceholders()).toBe("");
    });
  });

  describe("firstLetterUppercase", () => {
    it("should return the string with the first letter in uppercase", () => {
      expect(Utilities.firstLetterUppercase("test")).toBe("Test");
    });
    it("should return the empty string if no string is passed in", () => {
      expect(Utilities.firstLetterUppercase("")).toBe("");
    });
  });
  describe("isOverMax", () => {
    it("should return true if the value is over the count limit", () => {
      expect(Utilities.isOverMax(100, 80)).toBe(true);
    });
    it("should return false if the value is under the count limit", () => {
      expect(Utilities.isOverMax(80, 100)).toBe(false);
    });
    it("should return false if the value is the same as the count limit", () => {
      expect(Utilities.isOverMax(100, 100)).toBe(false);
    });
  });
  describe("setMaxCount", () => {
    it("should return - if the value is the empty string", () => {
      expect(Utilities.setMaxCount("", 80)).toBe("-");
    });
    it("should not return - if the value is 0", () => {
      const maxCount = Utilities.setMaxCount(0, 80);
      expect(maxCount).not.toBe("-");
      expect(maxCount).toBe(0);
    });
    it("should return the value if it is less than the countlimit", () => {
      expect(Utilities.setMaxCount(75, 80)).toBe(75);
    });
    it("should return the value if it is a string and less than the countlimit", () => {
      expect(Utilities.setMaxCount("75", 80)).toBe(75);
    });
    it("should return the value if it is equal to the countlimit", () => {
      expect(Utilities.setMaxCount(80, 80)).toBe(80);
    });
    it("should return the countlimit if the value is more than the countlimit", () => {
      expect(Utilities.setMaxCount(85, 80)).toBe(80);
    });
  });
  describe("isEmpty", () => {
    it("should return true if the value is the empty string", () => {
      expect(Utilities.isEmpty("")).toBe(true);
    });
    it("should return true if the value is undefined", () => {
      expect(Utilities.isEmpty()).toBe(true);
    });
    it("should return false if the value is a string", () => {
      expect(Utilities.isEmpty("test")).toBe(false);
    });
    it("should return false if the value is a number", () => {
      expect(Utilities.isEmpty(4)).toBe(false);
    });
    it("should return false if the value is an object", () => {
      expect(Utilities.isEmpty({ hello: true })).toBe(false);
    });
  });

  describe("getUrlParams", () => {
    it("should return given params (separated by &) in an object format", () => {
      expect(Utilities.getUrlParams("a=b&c=d")).toEqual({ a: "b", c: "d" });
    });
    it("should return given param in an object format", () => {
      expect(Utilities.getUrlParams("a=b")).toEqual({ a: "b" });
    });
    it("should return an empty object if = is not used", () => {
      expect(Utilities.getUrlParams("a+b")).toEqual({});
    });
    it("should strip the separator character and return given params (separated by &) in an object format", () => {
      expect(Utilities.getUrlParams("?a=b&c=d", "\\?")).toEqual({
        a: "b",
        c: "d"
      });
    });
    it("should strip the separator character and return given params (separated by &) in an object format", () => {
      expect(Utilities.getUrlParams("#a=b&c=d", "\\#")).toEqual({
        a: "b",
        c: "d"
      });
    });
  });

  describe("matchesStoredNonce", () => {
    it('should return true if the value passed matches the value stored against the key "nonce" in localstorage', () => {
      localStorage.setItem("nonce", "abcdefg");
      expect(Utilities.matchesStoredNonce("abcdefg")).toBe(true);
    });
    it('should return false if the value passed does not match the value stored against the key "nonce" in localstorage', () => {
      localStorage.setItem("nonce", "abcdefg");
      expect(Utilities.matchesStoredNonce("hijklmnop")).toBe(false);
    });
    it('should return false if there is no value stored against the key "nonce" in localstorage', () => {
      localStorage.removeItem("nonce");
      expect(Utilities.matchesStoredNonce("abcdefg")).toBe(false);
    });
  });
  describe("generateNonce", () => {
    it("should return a nonce of the length provided", () => {
      expect(Utilities.generateNonce(5).length).toBe(5);
    });
    it("should return an empty string if the length provided is 0", () => {
      let zeroLength = Utilities.generateNonce(0);
      expect(zeroLength).toBe("");
      expect(zeroLength.length).toBe(0);
    });
    it("should return an empty string if the length provided is less than 0", () => {
      let zeroLength = Utilities.generateNonce(-5);
      expect(zeroLength).toBe("");
      expect(zeroLength.length).toBe(0);
    });
  });

  describe("decodeURIMessage", () => {
    it("decodes URI Component, also replacing + signs with spaces", () => {
      const encodedMessage = "AADSTS90014%3a+The%2Brequired+field+%27nonce%27+is+missing.";
      const decodedMessage = "AADSTS90014: The+required field 'nonce' is missing.";
      expect(Utilities.decodeURIMessage(encodedMessage)).toEqual(decodedMessage);
    });
  });
  describe("getSelectedLocale", () => {
    it("returns passed default locale, if not saved in cookies", () => {
      document.cookie = "selectedLang=";
      expect(Utilities.getSelectedLocale("en")).toEqual("en");
    });
    it("returns the saved default lang locale", () => {
      document.cookie = "selectedLang=fr";
      expect(Utilities.getSelectedLocale("en")).toEqual("fr-FR");
    });
    it("returns the default locale as fr, if not present in the language map", () => {
      document.cookie = "selectedLang=ta";
      expect(Utilities.getSelectedLocale("fr")).toEqual("fr");
    });
    it("returns the locale as zh-TW when the saved language is zh_hant", () => {
      document.cookie = "selectedLang=zh_hant";
      expect(Utilities.getSelectedLocale("en")).toEqual("zh-TW");
    });
    it("returns the locale as zh-TW when the saved language is zh_hant and default is not passed", () => {
      document.cookie = "selectedLang=zh_hant";
      expect(Utilities.getSelectedLocale()).toEqual("zh-TW");
    });
  });
  describe("getSelectedLanguage", () => {
    it("returns passed default language, if not saved in cookies", () => {
      document.cookie = "selectedLang=";
      expect(Utilities.getSelectedLanguage("en")).toEqual("en");
    });
    it("returns the saved fr lang code", () => {
      document.cookie = "selectedLang=fr";
      expect(Utilities.getSelectedLanguage("en")).toEqual("fr");
    });
    it("returns the saved tamil lang code when the defaults is en", () => {
      document.cookie = "selectedLang=ta";
      expect(Utilities.getSelectedLanguage("en")).toEqual("ta");
    });
    it("returns the saved tamil lang code when the defaults is fr", () => {
      document.cookie = "selectedLang=ta";
      expect(Utilities.getSelectedLanguage("fr")).toEqual("ta");
    });
    it("returns the language as zh_hant when the saved language is zh_hant and default is not passed", () => {
      document.cookie = "selectedLang=zh_hant";
      expect(Utilities.getSelectedLanguage()).toEqual("zh_hant");
    });
  });
  describe("getSelectedLangAttribute", () => {
    it("returns passed default language, if not saved in cookies", () => {
      document.cookie = "selectedLang=";
      expect(Utilities.getSelectedLangAttribute("en")).toEqual("en");
    });
    it("returns the saved fr lang code", () => {
      document.cookie = "selectedLang=fr";
      expect(Utilities.getSelectedLangAttribute("en")).toEqual("fr");
    });
    it("returns the saved japanese lang code when the defaults is en", () => {
      document.cookie = "selectedLang=jp";
      expect(Utilities.getSelectedLangAttribute("en")).toEqual("ja");
    });
    it("returns the default code when an invalid language is passed in the cookie", () => {
      document.cookie = "selectedLang=ta";
      expect(Utilities.getSelectedLangAttribute("fr")).toEqual("fr");
    });
    it("returns the language as zh-hant when the saved language is zh_hant and default is not passed", () => {
      document.cookie = "selectedLang=zh_hant";
      expect(Utilities.getSelectedLangAttribute()).toEqual("zh-hant");
    });
  });
  describe("deepGet", () => {
    it("returns the value at the end of the path", () => {
      const someObj = {
        prop1: {
          prop2: {
            prop4: "prop4 value"
          },
          prop3: "prop3 value"
        },
        prop4: 0,
        prop5: false,
        prop6: ""
      };
      expect(Utilities.deepGet(["prop1", "prop2", "prop4"], someObj)).toEqual("prop4 value");
      expect(Utilities.deepGet(["prop1", "prop2"], someObj)).toEqual({
        prop4: "prop4 value"
      });
      expect(Utilities.deepGet(["prop4"], someObj)).toEqual(0);
      expect(Utilities.deepGet(["prop5"], someObj)).toEqual(false);
      expect(Utilities.deepGet(["prop6"], someObj)).toEqual("");
    });
    it("returns null if value not found or invalid values for path / originalScope", () => {
      const someObj = {
        prop1: "prop1 value",
        prop5: {
          prop6: "prop6 value"
        }
      };
      expect(Utilities.deepGet(["prop1", "prop2"], someObj)).toEqual(null);
      expect(Utilities.deepGet(["prop2"], someObj)).toEqual(null);
      expect(Utilities.deepGet(["prop2", "prop1"], someObj)).toEqual(null);
      expect(Utilities.deepGet(["prop5", "prop8", "prop10"], someObj)).toEqual(null);

      expect(Utilities.deepGet(["prop1"], {})).toEqual(null); // empty originalScope
      expect(Utilities.deepGet([], someObj)).toEqual(null); // empty path
      expect(Utilities.deepGet([], {})).toEqual(null);

      // originalScope must be a literal object
      expect(Utilities.deepGet(["prop1"], [1, 2])).toEqual(null);
      expect(Utilities.deepGet(["prop1"], 1)).toEqual(null); // truthy non-object
      expect(Utilities.deepGet(["prop1"], undefined)).toEqual(null); // falsy non-object

      // path must be an array
      expect(Utilities.deepGet(1, someObj)).toEqual(null); // truthy non-array
      expect(Utilities.deepGet(undefined, someObj)).toEqual(null); // falsy non-array

      // invalid values for both path and originalScope
      expect(Utilities.deepGet(1, 1)).toEqual(null);
      expect(Utilities.deepGet(undefined, undefined)).toEqual(null);
      expect(Utilities.deepGet(null, null)).toEqual(null);
    });
  });
  describe("checkAndSumProps", () => {
    it("sums upp all props with a number(numeric) value", () => {
      expect(Utilities.checkAndSumProps(1, 2, 3)).toEqual(6);
    });
    it("returns null if one of the props is not of numeric value", () => {
      expect(Utilities.checkAndSumProps(1, "2", 3)).toEqual(null);
    });
  });
  describe("deepCompareObjectProperties", () => {
    it("returns true if the passed object args have same exact structure", () => {
      const object1 = {
        prop1: "prop1 value",
        prop2: {
          prop3: "prop3 value"
        }
      };
      const object2 = {
        prop1: "prop1 value but different",
        prop2: {
          prop3: "prop3 value but different"
        }
      };
      expect(Utilities.deepCompareObjectProperties(object1, object2)).toBeTruthy();
    });
    it("throws error if the passed object args don't have same exact structure", () => {
      const object1 = {
        prop1: "prop1 value",
        prop2: {
          prop3: "prop3 value"
        }
      };
      const object2 = {
        prop1: "prop1 value but different",
        prop2: {
          prop3: "prop3 value but different",
          prop4: "oh this is extra info"
        }
      };
      try {
        Utilities.deepCompareObjectProperties(object1, object2);
      } catch (error) {
        expect(error).toBeTruthy();
      }
    });
  });
  describe("setOrigin", () => {
    // Sadly we can't test this function as jsdom won't let us remove that property
    // from window.location ☹️
    it("Leaves the origin alone if it already exist", () => {
      global.jsdom.reconfigure({
        url: "https://www.example.com/"
      });
      Utilities.setOrigin();
      expect(window.location.origin).toBe("https://www.example.com");
    });
  });
  describe("getCookies", () => {
    it("Returns cookies as object", () => {
      document.cookie = "regionSelected=MCC";
      const regionSelected = Utilities.getCookies().regionSelected;
      expect(regionSelected).toBe("MCC");
    });
  });

  describe("flattenObject", () => {
    it("object is null", () => {
      expect(() => {
        Utilities.flatten(null);
      }).toThrow(Error("flattenData: data is missing"));
    });
    it("object is not null", () => {
      const object = {
        test1: "test1",
        test2: "test2",
        deep: { deep1: "deep1", deep2: "deep2" }
      };
      const target = {
        test1: "test1",
        test2: "test2",
        "deep.deep1": "deep1",
        "deep.deep2": "deep2"
      };
      expect(Utilities.flatten(object)).toEqual(target);
    });
    it("object has array", () => {
      const object = {
        test1: "test1",
        test2: "test2",
        deep: [
          {
            deep1: "deep1",
            deep2: "deep2",
            deepNested: {
              deepNested: "deepNested1",
              deepNested2: "deepNested2"
            }
          }
        ]
      };
      const target = {
        test1: "test1",
        test2: "test2",
        "deep.0.deep1": "deep1",
        "deep.0.deep2": "deep2",
        "deep.0.deepNested.deepNested": "deepNested1",
        "deep.0.deepNested.deepNested2": "deepNested2"
      };
      expect(Utilities.flatten(object)).toEqual(target);
    });
  });
  describe("canAccess", () => {
    test.each`
      customerRoles         | nestedPropertyAccessor                 | element                          | decisionTables | specialRoles                                                       | expected
      ${[44, 5]}            | ${(rules) => rules.FEATURES.EXPORT}    | ${"submit-si"}                   | ${decisions}   | ${undefined}                                                       | ${true}
      ${[39, 41, 5, 6, 31]} | ${(rules) => rules.FEATURES.IMPORT}    | ${"delivery-order-status"}       | ${decisions}   | ${undefined}                                                       | ${true}
      ${[1, 2]}             | ${(rules) => rules.FEATURES.SUBMIT_SI} | ${"submit-si"}                   | ${decisions}   | ${undefined}                                                       | ${true}
      ${[1, 2, 3, 38]}      | ${(rules) => rules.FEATURES.SUBMIT_SI} | ${"resubmit-si"}                 | ${decisions}   | ${undefined}                                                       | ${true}
      ${[2]}                | ${(rules) => rules.FEATURES.SUBMIT_SI} | ${"resubmit-si"}                 | ${decisions}   | ${undefined}                                                       | ${false}
      ${[]}                 | ${(rules) => rules.TABS}               | ${"import"}                      | ${decisions}   | ${undefined}                                                       | ${false}
      ${[5, 6, 1, 14]}      | ${(rules) => rules.FEATURES.IMPORT}    | ${"add-customs-house-brokerage"} | ${decisions}   | ${undefined}                                                       | ${false}
      ${[1, 40, 15]}        | ${(rules) => rules.FEATURES.EXPORT}    | ${"missing-invoice-details"}     | ${decisions}   | ${undefined}                                                       | ${false}
      ${[4, 14]}            | ${(rules) => rules.FEATURES.IMPORT}    | ${"missing-invoice-details"}     | ${decisions}   | ${{ switchedShipper: null, switchedConsignee: null }}              | ${true}
      ${[4, 14, 15]}        | ${(rules) => rules.FEATURES.IMPORT}    | ${"missing-invoice-details"}     | ${decisions}   | ${{ switchedShipper: null, switchedConsignee: "A_CUSTOMER_CODE" }} | ${false}
      ${[3, 14]}            | ${(rules) => rules.FEATURES.EXPORT}    | ${"missing-invoice-details"}     | ${decisions}   | ${{ switchedShipper: "A_CUSTOMER_CODE", switchedConsignee: null }} | ${false}
      ${[3, 14]}            | ${(rules) => rules.FEATURES.EXPORT}    | ${"submit-si"}                   | ${decisions}   | ${{ switchedShipper: "A_CUSTOMER_CODE", switchedConsignee: null }} | ${false}
      ${[4, 14]}            | ${(rules) => rules.FEATURES.IMPORT}    | ${"surrender-b-l"}               | ${decisions}   | ${{ switchedShipper: null, switchedConsignee: "A_CUSTOMER_CODE" }} | ${false}
      ${[39, 14, 15]}       | ${(rules) => rules.FEATURES.IMPORT}    | ${"missing-invoice-details"}     | ${decisions}   | ${{ switchedShipper: null, switchedConsignee: "A_CUSTOMER_CODE" }} | ${true}
    `(
      "returns $expected for a logged user that has $customerRoles roles, trying to access the $element feature and $specialRoles set of special roles",
      ({ customerRoles, nestedPropertyAccessor, element, decisionTables, specialRoles, expected }) => {
        expect(Utilities.canAccess(customerRoles, nestedPropertyAccessor, element, decisionTables, specialRoles)).toBe(
          expected
        );
      }
    );
  });
  describe("canAccessError", () => {
    it("throws an error if the feature passed in doesn't exist", () => {
      expect.assertions(1);
      try {
        Utilities.canAccess([1, 40, 15], (rules) => rules.FEATURES.IMPORT, "catalin's-special-feature", decisions);
      } catch (e) {
        expect(e).toEqual(new Error("That feature doesn't exist!"));
      }
    });
  });
  describe("isMobilePlatform", () => {
    it("should return true if the query param has platform identifier 'platform=mobile'", () => {
      global.jsdom.reconfigure({
        url: "https://www.example.com/?platform=mobile"
      });
      expect(Utilities.isMobilePlatform()).toBeTruthy();
    });

    it("should return false if the query param has no platform identifier", () => {
      global.jsdom.reconfigure({
        url: "https://www.example.com/"
      });
      expect(Utilities.isMobilePlatform()).toBeFalsy();
    });
  });

  describe("isTwillSmeJourney", () => {
    it("should return true if localstorage has 'experience=maersk-go'", () => {
      setItem("custinfo", { type: "SBCO", experience: "maersk-go" });
      expect(Utilities.isTwillSmeJourney()).toBeTruthy();
    });

    it("should return false if localstorage not having 'experience=maersk-go'", () => {
      setItem("custinfo", null);
      expect(Utilities.isTwillSmeJourney()).toBeFalsy();
    });
  });
});
